
-- ============================================================
-- Steps for 6-8 month key recipes
-- ============================================================
INSERT INTO recipe_steps (id, recipe_id, step_no, title, description, image_url) VALUES
('step-v2-001', 'recipe-036', 1, '蒸南瓜', '南瓜去皮去籽，切成小块，放入蒸锅大火蒸12分钟至完全软烂。用筷子能轻松穿透即可。', 'https://images.unsplash.com/photo-1506084868230-bb9d95c24759?auto=format&fit=crop&w=600&q=80'),
('step-v2-002', 'recipe-036', 2, '研磨成泥', '将蒸熟的南瓜放入料理机或用研磨碗，加入少量温水，研磨成细腻无颗粒的泥状。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=600&q=80'),
('step-v2-003', 'recipe-036', 3, '混合米粉', '取适量婴儿高铁米粉，按包装说明用温水冲调好，再将南瓜泥拌入米糊中，调整至适合宝宝的稀稠度即可。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=600&q=80'),
('step-v2-004', 'recipe-037', 1, '蒸红薯', '红薯洗净去皮，切成2cm厚片，放入蒸锅大火蒸15-18分钟，蒸至完全软烂。', 'https://images.unsplash.com/photo-1596097635121-14b63b7a0c19?auto=format&fit=crop&w=600&q=80'),
('step-v2-005', 'recipe-037', 2, '压成泥', '趁热将红薯放入研磨碗，用研磨棒压成细腻泥状，加入少量温水或母乳调节稀稠度。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=600&q=80'),
('step-v2-006', 'recipe-037', 3, '过筛装碗', '过筛一遍确保无颗粒，盛入宝宝碗中，温度降至40°C以下即可喂食。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=600&q=80'),
('step-v2-007', 'recipe-040', 1, '选熟香蕉', '选择熟透的香蕉（表皮有黑点），去皮后取半根，切成小段。', 'https://images.unsplash.com/photo-1571771894821-ce9b6c11b08e?auto=format&fit=crop&w=600&q=80'),
('step-v2-008', 'recipe-040', 2, '压成泥', '用叉子将香蕉压成细腻泥状，或放入料理机打成泥。香蕉无需加热，保留更多营养。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=600&q=80'),
('step-v2-009', 'recipe-040', 3, '调节稠度', '如果太稠，加入少量母乳或温水调节。现做现吃，香蕉泥氧化变色后营养不变但外观不佳。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=600&q=80'),
('step-v2-010', 'recipe-045', 1, '煮鸡蛋', '鸡蛋冷水下锅，水开后煮8分钟至全熟，捞出放入冷水中冷却2分钟，剥壳。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=600&q=80'),
('step-v2-011', 'recipe-045', 2, '取蛋黄', '取出蛋黄，初次引入只取1/4个蛋黄，用研磨棒压成细腻粉末状。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=600&q=80'),
('step-v2-012', 'recipe-045', 3, '调成糊状', '加入少量温水或母乳，调成稀糊状。第一次只喂1/4个，观察48小时无过敏再逐步增加至整个蛋黄。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=600&q=80'),
('step-v2-013', 'recipe-046', 1, '量取米粉', '准备干净的宝宝碗，量取15克婴儿高铁米粉（约3平勺）。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=600&q=80'),
('step-v2-014', 'recipe-046', 2, '冲调米粉', '将60ml温水（约70°C）或母乳缓慢倒入米粉中，边倒边用勺子顺时针搅拌，避免结块。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=600&q=80'),
('step-v2-015', 'recipe-046', 3, '静置喂食', '搅拌至顺滑无颗粒，静置1分钟，温度降至40°C左右即可喂食。初次引入从1-2茶匙开始，逐步增加。', 'https://images.unsplash.com/photo-1506084868230-bb9d95c24759?auto=format&fit=crop&w=600&q=80'),
-- Steps for 9-11 month key recipes
('step-v2-016', 'recipe-066', 1, '处理鸡肉', '鸡胸肉洗净，冷水下锅焯水2分钟去腥，捞出后切成极小的碎末。大米提前浸泡30分钟。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=600&q=80'),
('step-v2-017', 'recipe-066', 2, '熬粥加肉', '锅中加入大米和足量水，大火烧开后转小火熬煮20分钟至米粒软烂，加入鸡肉末继续煮5分钟。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=600&q=80'),
('step-v2-018', 'recipe-066', 3, '加入蔬菜', '胡萝卜和西兰花切成细末，加入粥中再煮3分钟，搅拌均匀，温度适宜后喂食。', 'https://images.unsplash.com/photo-1506084868230-bb9d95c24759?auto=format&fit=crop&w=600&q=80'),
('step-v2-019', 'recipe-068', 1, '处理三文鱼', '三文鱼去皮去刺，切小块，加几滴柠檬汁腌制5分钟去腥，然后上锅蒸8分钟至熟透。', 'https://images.unsplash.com/photo-1467003909585-2f8a72700288?auto=format&fit=crop&w=600&q=80'),
('step-v2-020', 'recipe-068', 2, '蒸土豆', '土豆去皮切块，蒸15分钟至软烂，趁热压成细腻泥状，加入少量温水调节稀稠度。', 'https://images.unsplash.com/photo-1518977676601-b53f82aba655?auto=format&fit=crop&w=600&q=80'),
('step-v2-021', 'recipe-068', 3, '混合搅拌', '将蒸熟的三文鱼用叉子压碎，与土豆泥混合搅拌均匀，检查无鱼刺后即可喂食。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=600&q=80'),
('step-v2-022', 'recipe-069', 1, '准备食材', '南瓜去皮蒸熟后研磨成泥，取30克备用。鸡蛋打散，加入60ml温水搅拌均匀。', 'https://images.unsplash.com/photo-1506084868230-bb9d95c24759?auto=format&fit=crop&w=600&q=80'),
('step-v2-023', 'recipe-069', 2, '混合过筛', '将南瓜泥加入蛋液中，充分搅拌均匀，用细筛过滤一遍，去除气泡和颗粒。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=600&q=80'),
('step-v2-024', 'recipe-069', 3, '蒸制成型', '蒸锅水开后，将蛋液碗放入，盖上保鲜膜（扎几个小孔），中小火蒸10-12分钟至凝固，表面光滑即可。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=600&q=80'),
('step-v2-025', 'recipe-075', 1, '准备番茄粥', '番茄用开水烫30秒，去皮后切成小丁。大米提前浸泡30分钟，加水熬煮20分钟至软烂。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=600&q=80'),
('step-v2-026', 'recipe-075', 2, '加入番茄', '将番茄丁加入粥中，继续煮5分钟至番茄软烂出汁，用勺子轻轻压碎番茄块。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=600&q=80'),
('step-v2-027', 'recipe-075', 3, '打蛋花', '鸡蛋打散，沿锅边缓慢倒入粥中，边倒边搅拌形成蛋花，关火搅拌均匀，温度适宜后喂食。', 'https://images.unsplash.com/photo-1506084868230-bb9d95c24759?auto=format&fit=crop&w=600&q=80'),
('step-v2-028', 'recipe-084', 1, '煮软面条', '婴儿细面折成短段，锅中加水烧开，下面条煮8-10分钟至完全软烂，捞出备用。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=600&q=80'),
('step-v2-029', 'recipe-084', 2, '炒蔬菜蛋', '胡萝卜切成极细的碎末，锅中加少量水，将胡萝卜末煮软，打入鸡蛋搅散成蛋花。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=600&q=80'),
('step-v2-030', 'recipe-084', 3, '混合装碗', '将煮好的面条加入蔬菜蛋花汤中，搅拌均匀，确保面条足够软烂，温度适宜后喂食。', 'https://images.unsplash.com/photo-1506084868230-bb9d95c24759?auto=format&fit=crop&w=600&q=80')
ON CONFLICT DO NOTHING;
